        <div className="absolute top-0 left-0 w-full h-64 bg-gradient-to-b from-red-900/10 to-transparent pointer-events-none" />
        <div className="p-4 md:p-8 lg:p-12 max-w-7xl mx-auto">
          <AnimatePresence mode="wait">
            <motion.div
              key={activeTab}
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -10 }}
              transition={{ duration: 0.3 }}
            >
              {children}
