};

export default Layout;

import React from 'react';
import { motion } from 'framer-motion';
import { Shield, ArrowRight, User, MapPin, Building, Calendar } from 'lucide-react';
import { UserProfile, BuildingMaterial } from '../types';
import { TURKEY_CITIES_DATA, BUILDING_MATERIALS } from '../constants';

interface RegisterProps {
  onComplete: (profile: UserProfile) => void;
  onSkip: () => void;
}

const Register: React.FC<RegisterProps> = ({ onComplete, onSkip }) => {
  const [step, setStep] = React.useState(1);
  const [formData, setFormData] = React.useState<Partial<UserProfile>>({
    name: '',
    surname: '',
    city: 'İstanbul',
    district: '',
    age: 25,
    material: BuildingMaterial.ReinforcedConcrete,
    isRegistered: true
  });

  const nextStep = () => setStep(prev => prev + 1);
  const prevStep = () => setStep(prev => prev - 1);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onComplete(formData as UserProfile);
  };

  const containerVariants = {
    hidden: { opacity: 0, x: 20 },
    visible: { opacity: 1, x: 0 },
    exit: { opacity: 0, x: -20 }
  };

  return (
    <div className="min-h-screen flex items-center justify-center p-4 bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-slate-900 via-slate-950 to-black">
      <div className="absolute inset-0 overflow-hidden pointer-events-none">
        <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-red-900/20 blur-[120px] rounded-full" />
        <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-blue-900/10 blur-[120px] rounded-full" />
      </div>

      <motion.div 
        initial={{ scale: 0.9, opacity: 0 }}
        animate={{ scale: 1, opacity: 1 }}
        className="w-full max-w-xl bg-slate-900/50 backdrop-blur-xl border border-slate-800 rounded-3xl p-8 shadow-2xl relative z-10"
      >
        <div className="flex flex-col items-center mb-10">
          <motion.div 
            animate={{ rotate: [0, 5, -5, 0] }}
            transition={{ repeat: Infinity, duration: 4 }}
            className="bg-red-600 p-4 rounded-2xl shadow-xl shadow-red-600/20 mb-6"
          >
            <Shield className="w-10 h-10 text-white" />
          </motion.div>
          <h1 className="text-4xl font-bold title-font text-white mb-2">QuakeGuard'a Hoş Geldiniz</h1>
          <p className="text-slate-400 text-center">Güvenliğiniz için birkaç temel bilgiye ihtiyacımız var.</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          <AnimatePresence mode="wait">
            {step === 1 && (
              <motion.div key="step1" variants={containerVariants} initial="hidden" animate="visible" exit="exit" className="space-y-4">
                <div className="flex gap-4">
                  <div className="flex-1 space-y-2">
                    <label className="text-sm font-medium text-slate-400 ml-1">Adınız</label>
                    <div className="relative">
                      <User className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                      <input 
                        required
                        type="text" 
                        value={formData.name}
                        onChange={e => setFormData({...formData, name: e.target.value})}
                        className="w-full bg-slate-800/50 border border-slate-700 rounded-xl py-3 pl-10 pr-4 focus:ring-2 focus:ring-red-500 outline-none transition-all"
                        placeholder="Örn. Can"
                      />
                    </div>
                  </div>
                  <div className="flex-1 space-y-2">
                    <label className="text-sm font-medium text-slate-400 ml-1">Soyadınız</label>
                    <input 
                      required
                      type="text" 
                      value={formData.surname}
                      onChange={e => setFormData({...formData, surname: e.target.value})}
                      className="w-full bg-slate-800/50 border border-slate-700 rounded-xl py-3 px-4 focus:ring-2 focus:ring-red-500 outline-none transition-all"
                      placeholder="Örn. Yılmaz"
                    />
                  </div>
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-medium text-slate-400 ml-1">Yaşınız</label>
                  <div className="relative">
                    <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                    <input 
                      required
                      type="number" 
                      value={formData.age}
                      onChange={e => setFormData({...formData, age: parseInt(e.target.value)})}
                      className="w-full bg-slate-800/50 border border-slate-700 rounded-xl py-3 pl-10 pr-4 focus:ring-2 focus:ring-red-500 outline-none transition-all"
                    />
                  </div>
                </div>
                <button type="button" onClick={nextStep} className="w-full bg-red-600 hover:bg-red-700 text-white font-bold py-4 rounded-xl shadow-lg shadow-red-600/30 flex items-center justify-center gap-2 transition-all">
                  Devam Et <ArrowRight className="w-5 h-5" />
                </button>
              </motion.div>
            )}

            {step === 2 && (
              <motion.div key="step2" variants={containerVariants} initial="hidden" animate="visible" exit="exit" className="space-y-4">
                <div className="space-y-2">
                  <label className="text-sm font-medium text-slate-400 ml-1">Yaşadığınız Şehir</label>
                  <div className="relative">
                    <MapPin className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                    <select 
                      value={formData.city}
                      onChange={e => setFormData({...formData, city: e.target.value, district: ''})}
                      className="w-full bg-slate-800/50 border border-slate-700 rounded-xl py-3 pl-10 pr-4 focus:ring-2 focus:ring-red-500 outline-none appearance-none cursor-pointer"
                    >
                      {Object.keys(TURKEY_CITIES_DATA).map(city => (
                        <option key={city} value={city}>{city}</option>
                      ))}
                    </select>
                  </div>
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-medium text-slate-400 ml-1">İlçe</label>
                  <select 
                    required
                    value={formData.district}
                    onChange={e => setFormData({...formData, district: e.target.value})}
                    className="w-full bg-slate-800/50 border border-slate-700 rounded-xl py-3 px-4 focus:ring-2 focus:ring-red-500 outline-none appearance-none cursor-pointer"
                  >
                    <option value="">İlçe Seçiniz</option>
                    {(TURKEY_CITIES_DATA[formData.city || 'İstanbul'] || []).map(dist => (
                      <option key={dist} value={dist}>{dist}</option>
                    ))}
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-medium text-slate-400 ml-1">Bina Yapı Malzemesi</label>
                  <div className="relative">
                    <Building className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                    <select 
                      value={formData.material}
                      onChange={e => setFormData({...formData, material: e.target.value as BuildingMaterial})}
                      className="w-full bg-slate-800/50 border border-slate-700 rounded-xl py-3 pl-10 pr-4 focus:ring-2 focus:ring-red-500 outline-none appearance-none cursor-pointer"
                    >
                      {BUILDING_MATERIALS.map(mat => (
                        <option key={mat} value={mat}>{mat}</option>
                      ))}
                    </select>
                  </div>
                </div>
                <div className="flex gap-4">
                  <button type="button" onClick={prevStep} className="flex-1 bg-slate-800 hover:bg-slate-700 text-white font-bold py-4 rounded-xl transition-all">Geri</button>
                  <button type="submit" className="flex-[2] bg-red-600 hover:bg-red-700 text-white font-bold py-4 rounded-xl shadow-lg shadow-red-600/30 transition-all">Kaydı Tamamla</button>
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </form>

        <button 
          onClick={onSkip} 
          className="mt-8 w-full text-slate-500 hover:text-slate-300 text-sm font-medium transition-colors"
        >
          Şimdilik atla, sonra dolduracağım
        </button>
      </div>
    </div>
  );
};

export default Register;

