import React from 'react';
import { motion } from 'framer-motion';
import { User, Mail, MapPin, Building, Calendar, Edit3, Save } from 'lucide-react';
import { UserProfile, BuildingMaterial } from '../types';
import { TURKEY_CITIES_DATA, BUILDING_MATERIALS } from '../constants';

interface ProfileProps {
  profile: UserProfile;
  updateProfile: (profile: UserProfile) => void;
}

const Profile: React.FC<ProfileProps> = ({ profile, updateProfile }) => {
  const [isEditing, setIsEditing] = React.useState(false);
  const [formData, setFormData] = React.useState<UserProfile>(profile);

  const handleSave = () => {
    updateProfile(formData);
    setIsEditing(false);
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8">
      <div className="flex items-end justify-between border-b border-slate-800 pb-8">
        <div className="flex items-center gap-6">
          <div className="w-24 h-24 rounded-3xl bg-gradient-to-br from-red-600 to-orange-600 flex items-center justify-center text-white text-4xl font-bold shadow-xl shadow-red-600/20">
            {profile.name.charAt(0).toUpperCase()}
          </div>
          <div>
            <h2 className="text-4xl font-bold title-font">{profile.name} {profile.surname}</h2>
            <p className="text-slate-400">QuakeGuard Koruma Üyesi</p>
          </div>
        </div>
        <button 
          onClick={() => isEditing ? handleSave() : setIsEditing(true)}
          className={`flex items-center gap-2 px-6 py-3 rounded-xl font-bold transition-all ${
            isEditing ? 'bg-green-600 hover:bg-green-700 text-white' : 'bg-slate-800 hover:bg-slate-700 text-slate-100'
          }`}
        >
          {isEditing ? <><Save className="w-5 h-5" /> Kaydet</> : <><Edit3 className="w-5 h-5" /> Düzenle</>}
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="bg-slate-900 border border-slate-800 rounded-3xl p-8 space-y-6">
          <h3 className="text-xl font-bold title-font flex items-center gap-3">
            <User className="w-5 h-5 text-red-500" /> Kişisel Bilgiler
          </h3>
          <div className="space-y-4">
            <div className="space-y-1">
              <label className="text-xs text-slate-500 font-bold uppercase tracking-wider">Ad</label>
              {isEditing ? (
                <input 
