import React from 'react';
import { motion } from 'framer-motion';
import { MousePointer2, BrickWall as Wall, Sofa, Square, X, Info, Zap } from 'lucide-react';
import { GridCell, GridCellType } from '../types';

const GRID_SIZE = 12;

const FloorPlan: React.FC = () => {
  const [grid, setGrid] = React.useState<GridCell[]>(() => {
    const initialGrid: GridCell[] = [];
    for (let y = 0; y < GRID_SIZE; y++) {
      for (let x = 0; x < GRID_SIZE; x++) {
        initialGrid.push({ x, y, type: 'empty' });
      }
    }
    return initialGrid;
  });

  const [selectedTool, setSelectedTool] = React.useState<GridCellType>('wall');

  const updateCell = (x: number, y: number) => {
    setGrid(prev => prev.map(cell => 
      cell.x === x && cell.y === y 
        ? { ...cell, type: cell.type === selectedTool ? 'empty' : selectedTool } 
        : cell
    ));
  };

  // Safe zones (Life Triangles) are calculated automatically:
  // Must be adjacent to furniture, not on a wall, and not adjacent to a window.
  const calculateSafeZones = (currentGrid: GridCell[]) => {
    return currentGrid.map(cell => {
      if (cell.type === 'wall' || cell.type === 'window' || cell.type === 'furniture') {
        return cell;
      }

      // Check neighbors
      const neighbors = currentGrid.filter(n => 
        Math.abs(n.x - cell.x) <= 1 && Math.abs(n.y - cell.y) <= 1 && !(n.x === cell.x && n.y === cell.y)
      );

      const hasFurniture = neighbors.some(n => n.type === 'furniture');
      const nearWindow = neighbors.some(n => n.type === 'window');

      if (hasFurniture && !nearWindow) {
        return { ...cell, type: 'safe' as GridCellType };
      }

      return { ...cell, type: cell.type === 'safe' ? 'empty' : cell.type };
    });
  };

  const processedGrid = calculateSafeZones(grid);

  const resetGrid = () => {
    setGrid(grid.map(c => ({ ...c, type: 'empty' })));
  };

  const tools = [
    { id: 'wall', icon: Wall, label: 'Duvar', color: 'bg-slate-600' },
    { id: 'furniture', icon: Sofa, label: 'Dayanıklı Eşya', color: 'bg-orange-500' },
    { id: 'window', icon: Square, label: 'Pencere', color: 'bg-blue-400' },
  ];

  return (
    <div className="space-y-8">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h2 className="text-3xl font-bold title-font mb-2">Yaşam Üçgeni Planlayıcı</h2>
          <p className="text-slate-400">Odanızın planını çizin, en güvenli noktaları otomatik belirleyelim.</p>
        </div>
        <div className="flex bg-slate-900 border border-slate-800 p-1.5 rounded-2xl gap-2">
          {tools.map(tool => (
            <button
              key={tool.id}
              onClick={() => setSelectedTool(tool.id as GridCellType)}
              className={`flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-bold transition-all ${
                selectedTool === tool.id ? 'bg-red-600 text-white' : 'text-slate-400 hover:text-slate-200'
              }`}
            >
              <tool.icon className="w-4 h-4" /> {tool.label}
            </button>
          ))}
          <div className="w-[1px] bg-slate-800 mx-2" />
          <button onClick={resetGrid} className="p-2 text-slate-500 hover:text-red-500 transition-colors">
            <X className="w-5 h-5" />
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
        <div className="lg:col-span-3">
          <div 
            className="grid gap-1 bg-slate-800/30 p-2 rounded-3xl border border-slate-800 shadow-inner overflow-auto"
            style={{ gridTemplateColumns: `repeat(${GRID_SIZE}, minmax(0, 1fr))` }}
          >
            {processedGrid.map((cell, i) => (
              <motion.button
                key={`${cell.x}-${cell.y}`}
                whileHover={{ scale: 0.95 }}
                whileTap={{ scale: 0.9 }}
                onClick={() => updateCell(cell.x, cell.y)}
                className={`aspect-square rounded-md transition-all duration-300 relative ${
                  cell.type === 'empty' ? 'bg-slate-900/50 hover:bg-slate-800' :
                  cell.type === 'wall' ? 'bg-slate-400 shadow-[0_4px_0_rgb(100,116,139)] translate-y-[-4px]' :
                  cell.type === 'furniture' ? 'bg-orange-600 shadow-lg shadow-orange-900/20' :
                  cell.type === 'window' ? 'bg-blue-400 shadow-lg shadow-blue-900/20' :
                  cell.type === 'safe' ? 'bg-green-500 shadow-lg shadow-green-900/30 border-2 border-white/50' : ''
                }`}
              >
                {cell.type === 'safe' && (
                  <motion.div 
                    initial={{ scale: 0 }} 
                    animate={{ scale: 1 }} 
                    className="absolute inset-0 flex items-center justify-center"
                  >
                    <Zap className="w-4 h-4 text-white fill-white" />
                  </motion.div>
                )}
              </motion.button>
            ))}
          </div>
        </div>

        <div className="space-y-6">
          <div className="bg-slate-900 border border-slate-800 rounded-3xl p-6">
            <h3 className="font-bold mb-4 flex items-center gap-2">
              <Info className="w-5 h-5 text-blue-500" /> Nasıl Çalışır?
            </h3>
            <ol className="space-y-4 text-sm text-slate-400">
              <li className="flex gap-3">
                <span className="font-bold text-slate-100">1.</span>
                <span>Odanızın dış ve iç duvarlarını gri bloklarla belirleyin.</span>
              </li>
              <li className="flex gap-3">
                <span className="font-bold text-slate-100">2.</span>
                <span>Yatak, dolap, koltuk gibi sağlam mobilyaları turuncuyla yerleştirin.</span>
              </li>
              <li className="flex gap-3">
                <span className="font-bold text-slate-100">3.</span>
                <span>Pencereleri maviyle işaretleyin (Pencere önleri riskli bölgelerdir).</span>
              </li>
              <li className="flex gap-3">
                <span className="font-bold text-slate-100">4.</span>
                <span>Yeşil parlayan alanlar, <strong>Yaşam Üçgeni</strong> oluşturabileceğiniz güvenli noktalardır.</span>
              </li>
            </ol>
          </div>

          <div className="bg-gradient-to-br from-green-600/10 to-green-600/5 border border-green-500/20 rounded-3xl p-6">
            <div className="flex items-center gap-3 mb-2">
              <Zap className="w-5 h-5 text-green-500" />
              <h3 className="font-bold text-green-500">Akıllı Analiz</h3>
            </div>
            <p className="text-sm text-slate-300">
              Sistemimiz eşyaların dayanıklılığını ve pencerelerden gelebilecek cam kırığı riskini hesaplayarak güvenli bölgeleri anlık olarak günceller.
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

