            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full bg-transparent py-2 pl-10 pr-4 text-sm outline-none text-slate-200"
          />
        </div>
        <div className="h-48 overflow-y-auto custom-scrollbar p-1">
          {filteredItems.map((item) => (
            <button
              key={item}
              type="button"
