import React from 'react';
import { motion } from 'framer-motion';
import { BrainCircuit, Loader2, ShieldCheck, AlertCircle, RefreshCw } from 'lucide-react';
import { UserProfile, AIAnalysisResult } from '../types';
import { analyzeRisk } from '../services/geminiService';
import { PieChart, Pie, Cell, ResponsiveContainer } from 'recharts';
import RestrictedAccess from '../components/RestrictedAccess';

interface AIAnalyzeProps {
  profile: UserProfile;
  onStartRegistration?: () => void;
}

const AIAnalyze: React.FC<AIAnalyzeProps> = ({ profile, onStartRegistration }) => {
  const [loading, setLoading] = React.useState(false);
  const [result, setResult] = React.useState<AIAnalysisResult | null>(null);

  const runAnalysis = async () => {
    if (!profile.isRegistered) return;
    setLoading(true);
    const data = await analyzeRisk(profile);
    setResult(data);
    setLoading(false);
  };

  React.useEffect(() => {
    if (profile.isRegistered) {
      runAnalysis();
    }
  }, [profile.isRegistered]);

  if (!profile.isRegistered) {
    return <RestrictedAccess onAction={onStartRegistration || (() => {})} />;
  }

  const chartData = result ? [
    { name: 'Risk', value: result.riskPercent },
    { name: 'Safe', value: 100 - result.riskPercent }
  ] : [];

  const COLORS = ['#ef4444', '#1e293b'];

  return (
    <div className="max-w-5xl mx-auto space-y-8">
      <div className="text-center">
        <div className="inline-flex p-4 bg-red-600/10 rounded-3xl border border-red-500/20 mb-6">
          <BrainCircuit className="w-10 h-10 text-red-500" />
        </div>
        <h2 className="text-4xl font-bold title-font mb-4">AI Risk Analizi</h2>
        <p className="text-slate-400 max-w-xl mx-auto">Gemini 3 Yapay Zekası profil bilgilerinizi kullanarak konum ve yapı temelli bir risk değerlendirmesi yapar.</p>
      </div>

      {loading ? (
        <div className="flex flex-col items-center justify-center py-20 space-y-6">
          <motion.div
            animate={{ rotate: 360 }}
            transition={{ repeat: Infinity, duration: 1, ease: 'linear' }}
          >
            <Loader2 className="w-16 h-16 text-red-600" />
          </motion.div>
          <div className="space-y-2 text-center">
            <p className="text-xl font-bold">Veriler İşleniyor...</p>
            <p className="text-slate-500">Bölgesel fay hatları ve yapı özellikleri analiz ediliyor.</p>
          </div>
        </div>
      ) : result ? (
        <motion.div 
          initial={{ opacity: 0, scale: 0.95 }}
          animate={{ opacity: 1, scale: 1 }}
          className="grid grid-cols-1 lg:grid-cols-3 gap-8"
        >
          <div className="lg:col-span-1 bg-slate-900 border border-slate-800 rounded-3xl p-8 flex flex-col items-center justify-center relative overflow-hidden">
            <div className="absolute top-0 left-0 w-full h-1 bg-red-600" />
            <h3 className="text-xl font-bold mb-8">Tahmini Risk Skoru</h3>
            <div className="w-full h-48 relative">
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={chartData}
                    cx="50%"
                    cy="50%"
                    innerRadius={60}
                    outerRadius={80}
                    paddingAngle={5}
                    dataKey="value"
                    startAngle={180}
                    endAngle={0}
                  >
                    {chartData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} stroke="none" />
                    ))}
                  </Pie>
                </PieChart>
              </ResponsiveContainer>
              <div className="absolute inset-0 flex items-center justify-center pt-8">
                <span className="text-4xl font-black text-red-500">%{result.riskPercent}</span>
              </div>
            </div>
            <p className="text-center text-sm text-slate-400 mt-4 leading-relaxed">
              {result.riskPercent > 70 ? 'Yüksek öncelikli hazırlık yapmanız önerilir.' : 
               result.riskPercent > 40 ? 'Orta seviye riskli bölgedesiniz.' : 
               'Düşük seviye riskli bölgedesiniz.'}
            </p>
          </div>

          <div className="lg:col-span-2 space-y-8">
            <div className="bg-slate-900 border border-slate-800 rounded-3xl p-8">
              <h3 className="text-xl font-bold mb-4 flex items-center gap-2">
                <ShieldCheck className="w-6 h-6 text-green-500" /> AI Değerlendirme Özeti
              </h3>
              <p className="text-slate-300 leading-relaxed italic border-l-4 border-red-500 pl-6 py-2">
                "{result.summary}"
              </p>
            </div>

            <div className="bg-slate-900 border border-slate-800 rounded-3xl p-8">
              <h3 className="text-xl font-bold mb-6 flex items-center gap-2">
                <AlertCircle className="w-6 h-6 text-orange-500" /> Kişiselleştirilmiş Öneriler
              </h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {result.recommendations.map((rec, i) => (
                  <div key={i} className="flex gap-4 p-4 bg-slate-800/30 rounded-2xl border border-slate-700/30">
                    <div className="shrink-0 w-8 h-8 rounded-full bg-red-600/10 flex items-center justify-center text-red-500 font-bold text-sm">
                      {i + 1}
                    </div>
                    <p className="text-sm text-slate-300">{rec}</p>
                  </div>
                ))}
              </div>
            </div>

            <button 
              onClick={runAnalysis}
              className="w-full flex items-center justify-center gap-2 py-4 bg-slate-800 hover:bg-slate-700 rounded-2xl text-slate-100 font-bold transition-all"
            >
              <RefreshCw className="w-5 h-5" /> Analizi Yenile
            </button>
          </div>
        </motion.div>
      ) : (
        <div className="text-center py-10">
          <button onClick={runAnalysis} className="bg-red-600 text-white px-8 py-4 rounded-xl font-bold">Analizi Başlat</button>
        </div>
      )}
    </div>
  );
};

export default AIAnalyze;

