const TransitionCurtain: React.FC = () => {
  const panelCount = 5;

  // Geometrik figürler için rastgele veriler
  const shapes = React.useMemo(() => [...Array(15)].map((_, i) => ({
    id: i,
    size: Math.random() * 60 + 20,
    left: `${Math.random() * 100}%`,
    top: `${Math.random() * 100}%`,
    rotate: Math.random() * 360,
    type: i % 3 === 0 ? 'circle' : i % 3 === 1 ? 'square' : 'triangle',
  })), []);

  return (
    <div className="fixed inset-0 z-[200] pointer-events-none flex overflow-hidden">
      {/* Kademeli Geçiş Panelleri */}
      {[...Array(panelCount)].map((_, i) => (
        <motion.div
          key={i}
          initial={{ x: '-100%' }}
          animate={{ x: ['-100%', '0%', '0%', '100%'] }}
          transition={{
            duration: 1.2,
            times: [0, 0.4, 0.6, 1],
            ease: [0.87, 0, 0.13, 1], // Custom cubic-bezier for "snappy" feel
            delay: i * 0.05,
          }}
          className="h-full flex-1 bg-red-600 relative"
          style={{ 
            boxShadow: '0 0 50px rgba(0,0,0,0.3)',
            zIndex: panelCount - i 
          }}
        >
          {/* Panel içindeki süzülen dekoratif şekiller */}
          <div className="absolute inset-0 overflow-hidden opacity-30">
            {shapes.filter((_, idx) => idx % panelCount === i).map((shape) => (
              <motion.div
                key={shape.id}
                initial={{ opacity: 0, scale: 0 }}
                animate={{ 
                  opacity: [0, 1, 1, 0], 
                  scale: [0.5, 1.2, 1.2, 0.5],
                  y: [0, -100],
                  rotate: [shape.rotate, shape.rotate + 90]
                }}
                transition={{ duration: 1.2, ease: "easeInOut" }}
                className={`absolute border-2 border-white ${
                  shape.type === 'circle' ? 'rounded-full' : 
                  shape.type === 'square' ? 'rounded-lg' : ''
                }`}
                style={{
                  width: shape.size,
                  height: shape.size,
                  left: shape.left,
                  top: shape.top,
                  clipPath: shape.type === 'triangle' ? 'polygon(50% 0%, 0% 100%, 100% 100%)' : 'none',
                  borderStyle: shape.id % 2 === 0 ? 'solid' : 'dashed',
                }}
              />
            ))}
          </div>
        </motion.div>
      ))}

      {/* Merkezdeki Marka Reveal Animasyonu */}
      <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
        <div className="overflow-hidden">
          <motion.h2
            initial={{ y: "100%" }}
            animate={{ y: ["100%", "0%", "0%", "-100%"] }}
            transition={{ 
              duration: 1.2, 
              times: [0, 0.35, 0.65, 1], 
              ease: [0.87, 0, 0.13, 1] 
            }}
            className="text-white text-5xl md:text-7xl font-black title-font italic tracking-tighter"
          >
            QUAKEGUARD
          </motion.h2>
        </div>
      </div>
    </div>
  );
};

