import React from 'react';
import { motion } from 'framer-motion';

const CityBackground: React.FC = () => {
  // Rastgele bina verileri
  const buildings = React.useMemo(() => [...Array(10)].map((_, i) => ({
    id: i,
    width: 60 + Math.random() * 40,
    height: 100 + Math.random() * 150,
    color: ['bg-slate-200', 'bg-slate-300', 'bg-gray-200', 'bg-zinc-200'][i % 4],
    left: i * 10 + Math.random() * 2,
    windowColor: Math.random() > 0.5 ? 'bg-sky-100' : 'bg-white'
  })), []);

  const cars = React.useMemo(() => [...Array(5)].map((_, i) => ({
    id: i,
    speed: 15 + Math.random() * 10,
    delay: i * 3,
    direction: i % 2 === 0 ? 1 : -1,
    lane: i % 2,
    color: ['bg-red-500', 'bg-blue-500', 'bg-white', 'bg-yellow-400'][i % 4]
  })), []);

  const people = React.useMemo(() => [...Array(8)].map((_, i) => ({
    id: i,
    speed: 40 + Math.random() * 20,
    delay: i * 2,
    direction: i % 2 === 0 ? 1 : -1
  })), []);

  return (
    <div className="absolute inset-0 pointer-events-none z-0 overflow-hidden bg-sky-50 select-none">
      {/* Gökyüzü Gradiyenti (Hafif) */}
      <div className="absolute inset-0 bg-gradient-to-b from-sky-200 to-sky-50" />

      {/* Uzaktaki Şehir Silüeti (Hafif) */}
      <div className="absolute bottom-32 w-full flex items-end justify-between px-4 opacity-40">
        {buildings.map((b) => (
          <div
            key={b.id}
            className={`${b.color} border-t border-x border-slate-300 shadow-sm`}
            style={{ 
              width: b.width, 
              height: b.height,
            }}
          >
            {/* Pencere Izgarası */}
            <div className="grid grid-cols-3 gap-1 p-2 opacity-50">
              {[...Array(9)].map((_, wi) => (
                <div key={wi} className={`h-1.5 ${b.windowColor} rounded-sm`} />
              ))}
            </div>
          </div>
        ))}
      </div>

      {/* Zemin (Yol ve Kaldırım) */}
      <div className="absolute bottom-0 w-full h-32">
        {/* Yol (Siyah/Koyu Gri) */}
        <div className="absolute bottom-0 w-full h-24 bg-slate-800 border-t-4 border-slate-700">
          {/* Yol Çizgisi */}
          <div className="absolute top-1/2 left-0 w-full h-0.5 border-t-2 border-dashed border-slate-500/50" />
        </div>

        {/* Kaldırım (Gri) */}
        <div className="absolute bottom-24 w-full h-8 bg-slate-300 border-t border-slate-400" />

        {/* İnsanlar */}
        {people.map((p) => (
          <motion.div
            key={`person-${p.id}`}
            initial={{ x: p.direction === 1 ? '-5%' : '105%' }}
            animate={{ x: p.direction === 1 ? '105%' : '-5%' }}
            transition={{ duration: p.speed, repeat: Infinity, ease: "linear", delay: p.delay }}
            className="absolute bottom-24"
          >
            <div className="flex flex-col items-center">
              <div className="w-1.5 h-1.5 bg-slate-700 rounded-full" />
              <div className="w-2 h-4 bg-slate-600 rounded-t-sm" />
            </div>
          </motion.div>
        ))}

        {/* Arabalar */}
        {cars.map((c) => (
          <motion.div
            key={`car-${c.id}`}
            initial={{ x: c.direction === 1 ? '-15%' : '115%' }}
            animate={{ x: c.direction === 1 ? '115%' : '-15%' }}
            transition={{ duration: c.speed, repeat: Infinity, ease: "linear", delay: c.delay }}
            className="absolute"
            style={{ bottom: c.lane === 0 ? '8px' : '48px' }}
          >
            <div className={`relative w-12 h-5 ${c.color} rounded shadow-md border border-slate-700/20`}>
              <div className={`absolute top-1 w-1 h-2 bg-slate-100/80 ${c.direction === 1 ? 'right-0 rounded-l-sm' : 'left-0 rounded-r-sm'}`} />
              {/* Tekerlekler */}
              <div className="absolute -bottom-1 left-1 w-2 h-1 bg-black rounded-full" />
              <div className="absolute -bottom-1 right-1 w-2 h-1 bg-black rounded-full" />
            </div>
          </motion.div>
        ))}
      </div>

      {/* Hafif Atmosfer Parlaması */}
      <div className="absolute inset-0 bg-gradient-to-t from-white/20 to-transparent pointer-events-none" />
    </div>
  );
};

